import React, { useState } from 'react';

// --- BRAND COLORS ---
const gold = '#D4AF37';
const terracotta = '#C04000';
const black = '#000000';
const darkGrey = '#111111';

function App() {
  // 1. DATA: NOW WITH DETAILED BREAKDOWNS
  const platters = [
    { 
      id: 1, 
      name: "STARTER PACK", 
      price: "15,000", 
      desc: "4 Samosa, 4 Spring-roll, 4 Mosa, 3 Chicken.", // <--- EDIT BREAKDOWN HERE
      image: "starter.jpg" 
    },
    { 
      id: 2, 
      name: "SIGNATURE PLATTER", 
      price: "25,000", 
      desc: "10 Samosa, 10 Spring-roll, 10 Mosa, 5 Chicken.", // <--- EDIT BREAKDOWN HERE
      image: "signature.jpg" 
    },
    { 
      id: 3, 
      name: "OWAMBE SPECIAL", 
      price: "150,000", 
      desc: "70 Samosa, 70 Spring-roll, 60 Mosa, 50 Chicken.", // <--- EDIT BREAKDOWN HERE
      image: "owambe.jpg" 
    },
    { 
      id: 4, 
      name: "THE ÀMÍ SIGNATURE GRAND PLATTER", 
      price: "200,000", 
      desc: "Bespoke curation for 60+ guests. Premium assorted mix.", 
      image: "grand.jpg" 
    }
  ];

  const [cart, setCart] = useState([]);
  const [isCartOpen, setIsCartOpen] = useState(false);
  const [showBankDetails, setShowBankDetails] = useState(false);

  const addToCart = (item) => {
    setCart([...cart, item]);
    setIsCartOpen(true);
  };

  const removeFromCart = (index) => {
    const newCart = [...cart];
    newCart.splice(index, 1);
    setCart(newCart);
  };

  const total = cart.reduce((acc, item) => acc + parseInt(item.price.replace(/,/g, '')), 0);

  return (
    <div style={{ backgroundColor: black, minHeight: '100vh', color: '#fff', fontFamily: 'sans-serif', paddingBottom: '100px' }}>
      
      {/* HEADER */}
      <div style={{ padding: '40px 20px', textAlign: 'center' }}>
        <h1 style={{ fontSize: '1.5rem', fontWeight: 'bold', color: gold, letterSpacing: '4px', margin: 0 }}>ÀMÍ BY T</h1>
        <p style={{ fontSize: '0.6rem', color: '#666', marginTop: '5px', letterSpacing: '2px', textTransform: 'uppercase' }}>The Art of Taste</p>
      </div>

      {/* MENU LIST */}
      <div style={{ padding: '0 20px' }}>
        <h3 style={{ fontSize: '0.7rem', color: terracotta, textTransform: 'uppercase', letterSpacing: '2px', marginBottom: '20px' }}>Our Menu</h3>
        {platters.map((item) => (
          <div key={item.id} style={{ display: 'flex', backgroundColor: darkGrey, borderRadius: '15px', marginBottom: '15px', padding: '15px', alignItems: 'center', border: `1px solid #222` }}>
            <div style={{ width: '70px', height: '70px', backgroundColor: '#000', borderRadius: '10px', marginRight: '15px', overflow: 'hidden' }}>
                <img src={item.image} alt={item.name} style={{ width: '100%', height: '100%', objectFit: 'cover' }} onError={(e) => e.target.style.display = 'none'} />
            </div>
            <div style={{ flex: 1 }}>
              <h4 style={{ fontSize: '0.85rem', margin: '0', color: '#fff' }}>{item.name}</h4>
              <p style={{ fontSize: '0.65rem', color: '#888', margin: '4px 0', lineHeight: '1.4' }}>{item.desc}</p>
              <div style={{ fontSize: '1rem', fontWeight: 'bold', color: gold }}>₦{item.price}</div>
            </div>
            <button onClick={() => addToCart(item)} style={{ backgroundColor: terracotta, color: '#fff', border: 'none', borderRadius: '20px', padding: '8px 15px', fontSize: '0.65rem', fontWeight: 'bold' }}>ADD</button>
          </div>
        ))}
      </div>

      {/* CHECKOUT DRAWER */}
      {isCartOpen && (
        <div style={{ position: 'fixed', bottom: 0, left: 0, width: '100%', height: '100%', backgroundColor: 'rgba(0,0,0,0.9)', zIndex: 1000, display: 'flex', alignItems: 'flex-end' }}>
          <div style={{ width: '100%', backgroundColor: '#161616', borderTopLeftRadius: '30px', borderTopRightRadius: '30px', padding: '30px 20px', boxSizing: 'border-box' }}>
            
            <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: '25px' }}>
              <h3 style={{ color: gold, margin: 0 }}>{showBankDetails ? "Bank Transfer" : "Your Selection"}</h3>
              <button onClick={() => {setIsCartOpen(false); setShowBankDetails(false);}} style={{ background: 'none', border: 'none', color: '#fff', fontSize: '1.8rem' }}>✕</button>
            </div>

            {!showBankDetails ? (
              <>
                <div style={{ maxHeight: '30vh', overflowY: 'auto', marginBottom: '20px' }}>
                  {cart.map((item, index) => (
                    <div key={index} style={{ display: 'flex', justifyContent: 'space-between', padding: '15px 0', borderBottom: '1px solid #222' }}>
                      <div>
                        <div style={{ color: '#fff', fontSize: '0.9rem' }}>{item.name}</div>
                        <button onClick={() => removeFromCart(index)} style={{ background: 'none', border: 'none', color: terracotta, fontSize: '0.6rem', padding: 0 }}>Remove</button>
                      </div>
                      <span style={{ color: gold, fontWeight: 'bold' }}>₦{item.price}</span>
                    </div>
                  ))}
                </div>
                <div style={{ borderTop: '1px solid #333', paddingTop: '20px' }}>
                   <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: '25px' }}>
                    <span style={{ color: '#888' }}>Total</span>
                    <span style={{ color: '#fff', fontSize: '1.4rem', fontWeight: 'bold' }}>₦{total.toLocaleString()}</span>
                  </div>
                  <button onClick={() => setShowBankDetails(true)} style={{ width: '100%', padding: '18px', backgroundColor: gold, color: black, border: 'none', borderRadius: '15px', fontWeight: 'bold', marginBottom: '12px' }}>PAY VIA BANK TRANSFER</button>
                  <button onClick={() => window.open(`https://wa.me/YOURNUMBER?text=Order summary: ${cart.map(i => i.name).join(', ')}`)} style={{ width: '100%', padding: '18px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '15px', fontWeight: 'bold' }}>CONFIRM ON WHATSAPP</button>
                </div>
              </>
            ) : (
              <div style={{ textAlign: 'center', padding: '20px 0' }}>
                <p style={{ color: '#888', fontSize: '0.8rem' }}>Transfer total to:</p>
                <h2 style={{ color: gold, fontSize: '1.8rem', margin: '10px 0' }}>₦{total.toLocaleString()}</h2>
                <div style={{ backgroundColor: '#000', padding: '20px', borderRadius: '15px', border: `1px solid ${gold}33`, textAlign: 'left' }}>
                  <p style={{ margin: '8px 0', color: '#fff', fontSize: '0.9rem' }}><strong>Bank:</strong> GTBANK</p>
                  <p style={{ margin: '8px 0', color: '#fff', fontSize: '0.9rem' }}><strong>Account:</strong> 0123456789</p>
                  <p style={{ margin: '8px 0', color: '#fff', fontSize: '0.9rem' }}><strong>Name:</strong> ÀMÍ BY T CATERING</p>
                </div>
                <button onClick={() => window.open(`https://wa.me/YOURNUMBER?text=Receipt for order: ₦${total.toLocaleString()}`)} style={{ width: '100%', marginTop: '20px', padding: '15px', backgroundColor: '#25D366', color: '#fff', border: 'none', borderRadius: '12px', fontWeight: 'bold' }}>SEND PAYMENT RECEIPT</button>
                <button onClick={() => setShowBankDetails(false)} style={{ marginTop: '15px', background: 'none', border: 'none', color: '#666', textDecoration: 'underline', fontSize: '0.7rem' }}>Back to selection</button>
              </div>
            )}
          </div>
        </div>
      )}
    </div>
  );
}

export default App;
